void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("JanPetit_1");			link.l1 = StringFromKey("JanPetit_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("JanPetit_3");			link.l1 = StringFromKey("JanPetit_4");			link.l1.go = "exit_fight";			if (sti(pchar.money) >= 10000)			{				link.l2 = StringFromKey("JanPetit_5");				link.l2.go = "2";			}		break;		case "2":			AddMoneyToCharacter(pchar, -10000);			npchar.money = 10000;			dialog.text = StringFromKey("JanPetit_6");			link.l1 = "...";			link.l1.go = "exit";			AddDialogExitQuest("FL1_s36");		break;		case "exit_fight":			AddDialogExitQuest("FL1_s34_fight");			DialogExit();		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}